import { test as base, Page } from '@playwright/test';

export const APP_URL = 'https://hey-chill.vercel.app';

/**
 * Script injected before page load to replace Web Speech API with a
 * controllable mock. Exposes window.__mockRecognition for test control.
 */
export const MOCK_SPEECH_SCRIPT = `
(function() {
  class MockSpeechRecognition {
    constructor() {
      this.continuous = false;
      this.interimResults = false;
      this.lang = '';
      this.maxAlternatives = 1;
      this.onstart = null;
      this.onresult = null;
      this.onerror = null;
      this.onend = null;
      this._started = false;
      window.__mockRecognition = this;
    }

    start() {
      this._started = true;
      if (this.onstart) this.onstart();
    }

    stop() {
      this._started = false;
      if (this.onend) this.onend();
    }

    /** Simulate a speech result event */
    _fireResult(transcript, isFinal) {
      if (!this.onresult) return;
      const results = [[{ transcript: transcript }]];
      results[0].isFinal = !!isFinal;
      results.length = 1;
      this.onresult({ resultIndex: 0, results: results });
    }

    /** Simulate a recognition error */
    _fireError(errorCode) {
      if (this.onerror) this.onerror({ error: errorCode });
    }

    /** Simulate recognition ending on its own (e.g. network cut) */
    _fireEnd() {
      if (this.onend) this.onend();
    }
  }

  window.SpeechRecognition = MockSpeechRecognition;
  window.webkitSpeechRecognition = MockSpeechRecognition;
})();
`;

/** Navigate to the app with MockSpeechRecognition pre-installed. */
export async function gotoWithMock(page: Page) {
  await page.addInitScript(MOCK_SPEECH_SCRIPT);
  await page.goto(APP_URL);
}

/** Simulate a final speech result via the mock. */
export async function simulateSpeech(page: Page, transcript: string) {
  await page.evaluate(
    (t) => (window as any).__mockRecognition._fireResult(t, true),
    transcript,
  );
}

/** Simulate an interim (non-final) speech result. */
export async function simulateInterim(page: Page, transcript: string) {
  await page.evaluate(
    (t) => (window as any).__mockRecognition._fireResult(t, false),
    transcript,
  );
}

/** Click mic to start recording, wait for aria-pressed=true. */
export async function startRecording(page: Page) {
  await page.click('#mic-btn');
  await page.waitForFunction(
    () => document.getElementById('mic-btn')?.getAttribute('aria-pressed') === 'true',
  );
}

/** Click mic to stop recording, wait for aria-pressed=false. */
export async function stopRecording(page: Page) {
  await page.click('#mic-btn');
  await page.waitForFunction(
    () => document.getElementById('mic-btn')?.getAttribute('aria-pressed') === 'false',
  );
}

// Custom fixture type
type Fixtures = {
  mockPage: Page;
};

/** A page fixture that pre-installs the mock and navigates to the app. */
export const test = base.extend<Fixtures>({
  mockPage: async ({ page }, use) => {
    await gotoWithMock(page);
    await use(page);
  },
});

export { expect } from '@playwright/test';

