/**
 * UI Baseline Tests
 * Verifies page structure, initial state, and basic accessibility attributes.
 */
import { test, expect } from './fixtures';

test.describe('UI baseline', () => {
  test('page has correct title', async ({ mockPage: page }) => {
    await expect(page).toHaveTitle('Hey Chill');
  });

  test('header displays "Chill" heading', async ({ mockPage: page }) => {
    await expect(page.locator('h1')).toHaveText('Chill');
  });

  test('settings button is visible', async ({ mockPage: page }) => {
    await expect(page.locator('#settings-btn')).toBeVisible();
    await expect(page.locator('#settings-btn')).toHaveAttribute('aria-label', 'Settings');
  });

  test('mic button is visible with correct initial state', async ({ mockPage: page }) => {
    const btn = page.locator('#mic-btn');
    await expect(btn).toBeVisible();
    await expect(btn).toHaveAttribute('aria-label', 'Start recording');
    await expect(btn).toHaveAttribute('aria-pressed', 'false');
  });

  test('mic hint shows "Tap to speak" initially', async ({ mockPage: page }) => {
    await expect(page.locator('#mic-hint')).toHaveText('Tap to speak');
  });

  test('messages empty state is visible on first load', async ({ mockPage: page }) => {
    await expect(page.locator('#messages-empty')).toBeVisible();
    await expect(page.locator('#messages-empty p')).toContainText('Your messages will appear here');
  });

  test('transcript bar is hidden on load', async ({ mockPage: page }) => {
    await expect(page.locator('#transcript-bar')).toBeHidden();
  });

  test('live transcript is hidden on load', async ({ mockPage: page }) => {
    await expect(page.locator('#live-transcript')).toBeHidden();
  });
});

