/**
 * Push-to-Talk Tests
 * Covers mic button toggle behaviour and recording state UI changes.
 */
import { test, expect, startRecording, stopRecording, simulateSpeech } from './fixtures';

test.describe('Push-to-talk', () => {
  test('clicking mic transitions to recording state', async ({ mockPage: page }) => {
    await startRecording(page);
    await expect(page.locator('#mic-btn')).toHaveAttribute('aria-pressed', 'true');
  });

  test('recording state: mic hint changes to "Tap to stop"', async ({ mockPage: page }) => {
    await startRecording(page);
    await expect(page.locator('#mic-hint')).toHaveText('Tap to stop');
  });

  test('recording state: aria-label becomes "Stop recording"', async ({ mockPage: page }) => {
    await startRecording(page);
    await expect(page.locator('#mic-btn')).toHaveAttribute('aria-label', 'Stop recording');
  });

  test('recording state: live transcript panel becomes visible', async ({ mockPage: page }) => {
    await startRecording(page);
    await expect(page.locator('#live-transcript')).toBeVisible();
  });

  test('clicking mic again stops recording', async ({ mockPage: page }) => {
    await startRecording(page);
    await stopRecording(page);
    await expect(page.locator('#mic-btn')).toHaveAttribute('aria-pressed', 'false');
  });

  test('after stopping: live transcript is hidden', async ({ mockPage: page }) => {
    await startRecording(page);
    await stopRecording(page);
    await expect(page.locator('#live-transcript')).toBeHidden();
  });

  test('after stopping with transcript: transcript bar is shown', async ({ mockPage: page }) => {
    await startRecording(page);
    await simulateSpeech(page, 'hello world');
    await stopRecording(page);
    await expect(page.locator('#transcript-bar')).toBeVisible();
    await expect(page.locator('#transcript-text')).toHaveText('hello world');
  });

  test('after stopping without speech: transcript bar stays hidden', async ({ mockPage: page }) => {
    await startRecording(page);
    // No speech simulated
    await stopRecording(page);
    await expect(page.locator('#transcript-bar')).toBeHidden();
  });
});

