/**
 * Voice Activity Detection (VAD) Tests
 * Tests the 3500 ms silence auto-stop using page.clock fake timers.
 *
 * Strategy: page.clock.install() before navigation so that setTimeout calls
 * in app.js use fake time. The MockSpeechRecognition is also injected via
 * addInitScript before load.
 */
import { test as base, expect } from '@playwright/test';
import { APP_URL, MOCK_SPEECH_SCRIPT, startRecording } from './fixtures';

// VAD tests need clock installed before navigation — use a custom setup
const test = base;

test.describe('VAD silence auto-stop', () => {
  test('auto-stops recording after 3500 ms of silence', async ({ page }) => {
    await page.clock.install();
    await page.addInitScript(MOCK_SPEECH_SCRIPT);
    await page.goto(APP_URL);

    await startRecording(page);
    await expect(page.locator('#mic-btn')).toHaveAttribute('aria-pressed', 'true');

    await page.clock.runFor(3500);

    await expect(page.locator('#mic-btn')).toHaveAttribute('aria-pressed', 'false');
  });

  test('silence timer resets when speech arrives, delaying auto-stop', async ({ page }) => {
    await page.clock.install();
    await page.addInitScript(MOCK_SPEECH_SCRIPT);
    await page.goto(APP_URL);

    await startRecording(page);

    // Advance 2000 ms — still within the first 3500 ms window
    await page.clock.runFor(2000);
    await expect(page.locator('#mic-btn')).toHaveAttribute('aria-pressed', 'true');

    // Speech arrives — resets the 3500 ms timer
    await page.evaluate(() => (window as any).__mockRecognition._fireResult('hello', true));

    // Advance another 2000 ms (total 4000 ms, but only 2000 since last speech)
    await page.clock.runFor(2000);
    // Should still be recording
    await expect(page.locator('#mic-btn')).toHaveAttribute('aria-pressed', 'true');

    // Advance the remaining 1500 ms — total 3500 ms after last speech
    await page.clock.runFor(1500);
    await expect(page.locator('#mic-btn')).toHaveAttribute('aria-pressed', 'false');
  });

  test('after VAD auto-stop, transcript bar shows the captured text', async ({ page }) => {
    await page.clock.install();
    await page.addInitScript(MOCK_SPEECH_SCRIPT);
    await page.goto(APP_URL);

    await startRecording(page);
    await page.evaluate(() => (window as any).__mockRecognition._fireResult('voice activity test', true));

    await page.clock.runFor(3500);

    await expect(page.locator('#transcript-bar')).toBeVisible();
    await expect(page.locator('#transcript-text')).toContainText('voice activity test');
  });

