/* ===== Reset & Base ===== */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --bg: #1a1a2e;
  --bg-2: #16213e;
  --bg-3: #0f3460;
  --accent: #e94560;
  --accent-glow: rgba(233, 69, 96, 0.4);
  --accent-2: #533483;
  --text: #e0e0f0;
  --text-muted: #8888aa;
  --surface: rgba(255, 255, 255, 0.06);
  --surface-hover: rgba(255, 255, 255, 0.10);
  --border: rgba(255, 255, 255, 0.08);
  --radius: 16px;
  --radius-sm: 10px;
  --transition: 0.2s ease;
  --mic-size: 88px;
  --ring-size: 128px;
}

html, body {
  height: 100%;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
  -webkit-tap-highlight-color: transparent;
  overscroll-behavior: none;
}

#app {
  display: flex;
  flex-direction: column;
  height: 100dvh;
  max-width: 480px;
  margin: 0 auto;
  position: relative;
}

/* ===== Header ===== */
.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 20px 12px;
  background: linear-gradient(180deg, var(--bg) 0%, transparent 100%);
  position: relative;
  z-index: 10;
  flex-shrink: 0;
}

.header-title {
  display: flex;
  align-items: center;
  gap: 10px;
}

.logo-dot {
  width: 10px;
  height: 10px;
  background: var(--accent);
  border-radius: 50%;
  box-shadow: 0 0 8px var(--accent-glow);
  animation: pulse-dot 3s ease-in-out infinite;
}

@keyframes pulse-dot {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.6; transform: scale(0.85); }
}

.header h1 {
  font-size: 1.25rem;
  font-weight: 700;
  letter-spacing: 0.03em;
  color: var(--text);
}

.icon-btn {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text-muted);
  border-radius: 50%;
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: background var(--transition), color var(--transition);
}

.icon-btn svg {
  width: 18px;
  height: 18px;
}

.icon-btn:hover, .icon-btn:focus-visible {
  background: var(--surface-hover);
  color: var(--text);
  outline: none;
}

/* ===== Messages ===== */
.messages {
  flex: 1;
  overflow-y: auto;
  padding: 12px 20px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: thin;
  scrollbar-color: var(--border) transparent;
}

.messages::-webkit-scrollbar {
  width: 4px;
}

.messages::-webkit-scrollbar-track {
  background: transparent;
}

.messages::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 2px;
}

.messages-empty {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
}

.messages-empty p {
  color: var(--text-muted);
  font-size: 0.9rem;
  text-align: center;
}

/* Message bubble */
.message {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  border-bottom-right-radius: 4px;
  padding: 12px 16px;
  max-width: 100%;
  word-break: break-word;
  animation: slide-up 0.25s ease both;
}

.message.sending {
  opacity: 0.6;
}

.message.sent {
  border-color: rgba(233, 69, 96, 0.2);
}

.message.error {
  border-color: rgba(255, 80, 80, 0.3);
}

.message-text {
  font-size: 0.95rem;
  line-height: 1.5;
  color: var(--text);
}

.message-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 6px;
}

.message-time {
  font-size: 0.75rem;
  color: var(--text-muted);
}

.message-status {
  font-size: 0.72rem;
  padding: 2px 7px;
  border-radius: 20px;
  background: var(--surface);
  color: var(--text-muted);
}

.message.sent .message-status {
  background: rgba(233, 69, 96, 0.15);
  color: var(--accent);
}

.message.error .message-status {
  background: rgba(255, 80, 80, 0.15);
  color: #ff6b6b;
}

@keyframes slide-up {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ===== Live Transcript ===== */
.live-transcript {
  margin: 0 20px 8px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
  animation: fade-in 0.2s ease;
}

.live-transcript p {
  font-size: 0.92rem;
  color: var(--text-muted);
  font-style: italic;
  line-height: 1.5;
  min-height: 1.4em;
}

.live-transcript p.has-text {
  color: var(--text);
  font-style: normal;
}

/* ===== Transcript Bar (post-recording) ===== */
.transcript-bar {
  margin: 0 20px 12px;
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
  animation: slide-up 0.2s ease;
}

.transcript-text {
  font-size: 0.95rem;
  line-height: 1.5;
  color: var(--text);
  margin-bottom: 14px;
  word-break: break-word;
}

.transcript-actions {
  display: flex;
  gap: 10px;
  justify-content: flex-end;
}

/* ===== Buttons ===== */
.btn-ghost {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-muted);
  border-radius: var(--radius-sm);
  padding: 8px 18px;
  font-size: 0.9rem;
  cursor: pointer;
  transition: all var(--transition);
}

.btn-ghost:hover, .btn-ghost:focus-visible {
  background: var(--surface);
  color: var(--text);
  outline: none;
}

.btn-send {
  background: var(--accent);
  border: none;
  color: #fff;
  border-radius: var(--radius-sm);
  padding: 8px 22px;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: all var(--transition);
  box-shadow: 0 2px 12px rgba(233, 69, 96, 0.35);
}

.btn-send:hover, .btn-send:focus-visible {
  background: #ff5c75;
  outline: none;
  box-shadow: 0 4px 20px rgba(233, 69, 96, 0.55);
}

/* ===== Mic Section ===== */
.mic-section {
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 16px 20px 36px;
  gap: 16px;
}

.mic-hint {
  font-size: 0.85rem;
  color: var(--text-muted);
  letter-spacing: 0.04em;
  transition: color var(--transition);
  min-height: 1.2em;
}

.mic-hint.active {
  color: var(--accent);
}

/* Dual-mode button container */
.mic-buttons {
  display: flex;
  align-items: flex-start;
  justify-content: center;
  gap: 28px;
}

.mode-btn-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.mode-label {
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-muted);
  transition: color var(--transition);
}

.mode-label.brainstorm-label {
  color: rgba(163, 121, 221, 0.7);
}

/* Shrink buttons slightly for side-by-side layout */
.mic-buttons .mic-ring {
  width: 112px;
  height: 112px;
}

.mic-buttons .mic-btn {
  width: 76px;
  height: 76px;
}

.mic-buttons .mic-icon {
  width: 30px;
  height: 30px;
}

/* Ring / glow around button */
.mic-ring {
  position: relative;
  width: var(--ring-size);
  height: var(--ring-size);
  display: flex;
  align-items: center;
  justify-content: center;
}

.mic-ring::before,
.mic-ring::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 2px solid transparent;
  transition: all 0.3s ease;
}

.mic-ring.recording::before {
  border-color: var(--accent-glow);
  animation: ring-pulse 1.4s ease-in-out infinite;
}

.mic-ring.recording::after {
  border-color: rgba(233, 69, 96, 0.15);
  animation: ring-pulse 1.4s ease-in-out 0.7s infinite;
}

@keyframes ring-pulse {
  0%   { transform: scale(1); opacity: 1; }
  100% { transform: scale(1.6); opacity: 0; }
}

/* The mic button */
.mic-btn {
  position: relative;
  width: var(--mic-size);
  height: var(--mic-size);
  border-radius: 50%;
  border: none;
  background: linear-gradient(145deg, var(--bg-3), var(--accent-2));
  color: #fff;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow:
    0 4px 24px rgba(0, 0, 0, 0.4),
    0 0 0 1px rgba(255, 255, 255, 0.08);
  transition: transform 0.15s ease, box-shadow 0.15s ease;
  -webkit-user-select: none;
  user-select: none;
  touch-action: manipulation;
  z-index: 1;
}

.mic-btn:hover {
  transform: scale(1.05);
  box-shadow:
    0 6px 32px rgba(0, 0, 0, 0.5),
    0 0 0 1px rgba(255, 255, 255, 0.12);
}

.mic-btn:active {
  transform: scale(0.96);
}

.mic-btn:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 4px;
}

.mic-btn.recording {
  background: linear-gradient(145deg, var(--accent), #c0392b);
  box-shadow:
    0 4px 32px var(--accent-glow),
    0 0 0 1px rgba(233, 69, 96, 0.3);
  animation: mic-glow 1.4s ease-in-out infinite alternate;
}

@keyframes mic-glow {
  from { box-shadow: 0 4px 24px var(--accent-glow), 0 0 0 1px rgba(233, 69, 96, 0.3); }
  to   { box-shadow: 0 4px 48px rgba(233, 69, 96, 0.7), 0 0 0 1px rgba(233, 69, 96, 0.5); }
}

.mic-icon {
  width: 36px;
  height: 36px;
  transition: transform var(--transition);
}

.mic-btn.recording .mic-icon {
  transform: scale(1.1);
}

/* ===== Brainstorm button colour overrides ===== */
.mic-btn.brainstorm-btn {
  background: linear-gradient(145deg, var(--bg-3), var(--accent-2));
}

.mic-btn.brainstorm-btn:hover {
  transform: scale(1.05);
}

.mic-btn.brainstorm-btn.recording {
  background: linear-gradient(145deg, var(--accent-2), #7b2fbe);
  box-shadow:
    0 4px 32px rgba(83, 52, 131, 0.55),
    0 0 0 1px rgba(163, 121, 221, 0.35);
  animation: brainstorm-glow 1.4s ease-in-out infinite alternate;
}

@keyframes brainstorm-glow {
  from { box-shadow: 0 4px 24px rgba(83, 52, 131, 0.4),  0 0 0 1px rgba(163, 121, 221, 0.3); }
  to   { box-shadow: 0 4px 48px rgba(83, 52, 131, 0.75), 0 0 0 1px rgba(163, 121, 221, 0.55); }
}

/* Brainstorm ring pulses in purple when recording */
.mic-ring.brainstorm-ring.recording::before {
  border-color: rgba(163, 121, 221, 0.55);
}

.mic-ring.brainstorm-ring.recording::after {
  border-color: rgba(163, 121, 221, 0.2);
}

/* Active mode label colours */
.mic-hint.active.brainstorm-active {
  color: rgba(163, 121, 221, 1);
}

/* ===== Not supported ===== */
.not-supported {
  margin: 0 20px 20px;
  background: rgba(255, 80, 80, 0.1);
  border: 1px solid rgba(255, 80, 80, 0.25);
  border-radius: var(--radius);
  padding: 14px 16px;
  text-align: center;
  font-size: 0.9rem;
  color: #ff9999;
}

/* ===== Modal ===== */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.65);
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  display: flex;
  align-items: flex-end;
  justify-content: center;
  z-index: 100;
  animation: fade-in 0.2s ease;
}

.modal-overlay[hidden] {
  display: none;
}

.modal {
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius) var(--radius) 0 0;
  width: 100%;
  max-width: 480px;
  padding: 0;
  animation: slide-modal 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

@media (min-height: 600px) {
  .modal-overlay {
    align-items: center;
  }
  .modal {
    border-radius: var(--radius);
    max-width: 420px;
  }
}

@keyframes slide-modal {
  from { transform: translateY(40px); opacity: 0; }
  to   { transform: translateY(0); opacity: 1; }
}

.modal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 20px 16px;
  border-bottom: 1px solid var(--border);
}

.modal-header h2 {
  font-size: 1.1rem;
  font-weight: 600;
}

.modal-body {
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.modal-body label {
  font-size: 0.85rem;
  color: var(--text-muted);
  font-weight: 500;
}

.modal-body input {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text);
  font-size: 0.95rem;
  padding: 12px 14px;
  width: 100%;
  transition: border-color var(--transition);
  font-family: inherit;
}

.modal-body input::placeholder {
  color: var(--text-muted);
}

.modal-body input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 2px rgba(233, 69, 96, 0.15);
}

.field-hint {
  font-size: 0.78rem;
  color: var(--text-muted);
}

.modal-footer {
  padding: 16px 20px 24px;
  display: flex;
  justify-content: flex-end;
}

/* ===== Header actions ===== */
.header-actions {
  display: flex;
  align-items: center;
  gap: 8px;
}

/* ===== Passive listening state (wake mode on, waiting for wake word) ===== */
.mic-ring.listening-passive::before {
  border-color: rgba(83, 52, 131, 0.5);
  animation: ring-breathe 2.8s ease-in-out infinite;
}

.mic-ring.listening-passive::after {
  border-color: rgba(83, 52, 131, 0.2);
  animation: ring-breathe 2.8s ease-in-out 1.4s infinite;
}

.mic-ring.listening-passive .mic-btn {
  animation: passive-glow 2.8s ease-in-out infinite alternate;
}

@keyframes ring-breathe {
  0%, 100% { transform: scale(1);    opacity: 0.7; }
  50%       { transform: scale(1.4); opacity: 0; }
}

@keyframes passive-glow {
  from { box-shadow: 0 4px 24px rgba(0, 0, 0, 0.4), 0 0 0 1px rgba(83, 52, 131, 0.15); }
  to   { box-shadow: 0 4px 32px rgba(83, 52, 131, 0.25), 0 0 0 3px rgba(83, 52, 131, 0.35); }
}

/* Wake word button active state */
.icon-btn.wake-active {
  color: var(--accent);
  background: rgba(233, 69, 96, 0.12);
  border-color: rgba(233, 69, 96, 0.3);
  animation: wake-btn-pulse 2.5s ease-in-out infinite;
}

@keyframes wake-btn-pulse {
  0%, 100% { box-shadow: 0 0 0 0 rgba(233, 69, 96, 0); }
  50%       { box-shadow: 0 0 0 4px rgba(233, 69, 96, 0.15); }
}

/* ===== Utilities ===== */
@keyframes fade-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

/* Safe area for notch phones */
@supports (padding-bottom: env(safe-area-inset-bottom)) {
  .mic-section {
    padding-bottom: calc(36px + env(safe-area-inset-bottom));
  }
}

input.content:
/**
 * Dual-Mode UI Tests — FRG-211
 *
 * Covers the replacement of the single mic button with side-by-side
 * Quick (VAD-based) and Brainstorm (continuous) buttons.
 *
 * Tests run against the feature/FRG-211-dual-mode-ui-quick-brainstorm branch
 * served locally at http://localhost:9090.
 *
 * Test scenarios from the acceptance criteria:
 *  1. Page loads → two buttons visible side-by-side ("Quick", "Brainstorm")
 *  2. Quick button → starts recording (aria-pressed=true), auto-stops after 3500 ms silence
 *  3. Brainstorm button → starts recording, does NOT auto-stop on silence
 *  4. Brainstorm → tap again to manually stop → shows transcript
 *  5. Only one mode can be active at a time
 *  6. ARIA labels are correct on load and during recording
 *  7. Hint text changes correctly per active mode
 *  8. Buttons fit side-by-side on a 360 px mobile viewport (no overflow)
 *  9. Wake word "Hey Chill" triggers Quick mode specifically
 */

import { test as base, expect, Page } from '@playwright/test';
import { MOCK_SPEECH_SCRIPT } from './fixtures';

/* ===== Constants ===== */
const PR_URL = 'http://localhost:9090';

/**
 * Enhanced mock that tracks every SpeechRecognition instance created so tests
 * can target the wake-word recognition separately from the main recognition.
 * window.__mockInstances[0] → main recognition
 * window.__mockInstances[1] → wake recognition (created after wake mode enabled)
 */
const MULTI_INSTANCE_MOCK_SCRIPT = `
(function() {
  const instances = [];

  class MockSpeechRecognition {
    constructor() {
      this.continuous = false;
      this.interimResults = false;
      this.lang = '';
      this.maxAlternatives = 1;
      this.onstart = null;
      this.onresult = null;
      this.onerror = null;
      this.onend = null;
      this._started = false;
      instances.push(this);
      window.__mockInstances = instances;
      window.__mockRecognition = this; // latest instance (convenience)
    }

    start() {
      this._started = true;
      if (this.onstart) this.onstart();
    }

    stop() {
      this._started = false;
      if (this.onend) this.onend();
    }

    _fireResult(transcript, isFinal) {
      if (!this.onresult) return;
      const results = [[{ transcript: transcript }]];
      results[0].isFinal = !!isFinal;
      results.length = 1;
      this.onresult({ resultIndex: 0, results: results });
    }

    _fireError(errorCode) {
      if (this.onerror) this.onerror({ error: errorCode });
    }

    _fireEnd() {
      if (this.onend) this.onend();
    }
  }

  window.SpeechRecognition = MockSpeechRecognition;
  window.webkitSpeechRecognition = MockSpeechRecognition;
})();
`;

/* ===== Helpers ===== */

async function gotoWithMock(page: Page) {
  await page.addInitScript(MOCK_SPEECH_SCRIPT);
  await page.goto(PR_URL);
}

async function gotoWithMultiMock(page: Page) {
  await page.addInitScript(MULTI_INSTANCE_MOCK_SCRIPT);
  await page.goto(PR_URL);
}

async function simulateSpeech(page: Page, transcript: string) {
  await page.evaluate(
    (t) => (window as any).__mockRecognition._fireResult(t, true),
    transcript,
  );
}

async function startQuick(page: Page) {
  await page.click('#quick-btn');
  await page.waitForFunction(
    () => document.getElementById('quick-btn')?.getAttribute('aria-pressed') === 'true',
  );
}

async function startBrainstorm(page: Page) {
  await page.click('#brainstorm-btn');
  await page.waitForFunction(
    () => document.getElementById('brainstorm-btn')?.getAttribute('aria-pressed') === 'true',
  );
}

async function stopBrainstorm(page: Page) {
  await page.click('#brainstorm-btn');
  await page.waitForFunction(
    () => document.getElementById('brainstorm-btn')?.getAttribute('aria-pressed') === 'false',
  );
}

/* ===== Custom fixture ===== */

type Fixtures = { mockPage: Page };

const test = base.extend<Fixtures>({
  mockPage: async ({ page }, use) => {
    await gotoWithMock(page);
    await use(page);
  },
});

/* ================================================================
 * 1. Page layout — both buttons visible side-by-side
 * ================================================================ */

test.describe('Dual-mode layout', () => {
  test('Quick and Brainstorm buttons are both visible on load', async ({ mockPage: page }) => {
    await expect(page.locator('#quick-btn')).toBeVisible();
    await expect(page.locator('#brainstorm-btn')).toBeVisible();
  });

  test('mode labels show "Quick" and "Brainstorm" text', async ({ mockPage: page }) => {
    // First .mode-label is "Quick", second (brainstorm-label) is "Brainstorm"
    await expect(page.locator('.mode-label').first()).toHaveText('Quick');
    await expect(page.locator('.brainstorm-label')).toHaveText('Brainstorm');
  });

  test('buttons are rendered side-by-side in the same row', async ({ mockPage: page }) => {
    const quickBox      = await page.locator('#quick-btn').boundingBox();
    const brainstormBox = await page.locator('#brainstorm-btn').boundingBox();

    expect(quickBox).not.toBeNull();
    expect(brainstormBox).not.toBeNull();

    // Vertically aligned (centers within 30 px of each other)
    const quickCenterY      = quickBox!.y + quickBox!.height / 2;
    const brainstormCenterY = brainstormBox!.y + brainstormBox!.height / 2;
    expect(Math.abs(quickCenterY - brainstormCenterY)).toBeLessThan(30);

    // Quick is to the left of Brainstorm
    expect(quickBox!.x).toBeLessThan(brainstormBox!.x);
  });

  test('both buttons fit within a 360 px mobile viewport (no overflow)', async ({ page }) => {
    await page.setViewportSize({ width: 360, height: 800 });
    await gotoWithMock(page);

    const quickBox      = await page.locator('#quick-btn').boundingBox();
    const brainstormBox = await page.locator('#brainstorm-btn').boundingBox();

    expect(quickBox).not.toBeNull();
    expect(brainstormBox).not.toBeNull();

    // Right edge of each button must be within the 360 px viewport
    expect(quickBox!.x + quickBox!.width).toBeLessThanOrEqual(360);
    expect(brainstormBox!.x + brainstormBox!.width).toBeLessThanOrEqual(360);

    // Both buttons must actually be visible (left edge ≥ 0)
    expect(quickBox!.x).toBeGreaterThanOrEqual(0);
    expect(brainstormBox!.x).toBeGreaterThanOrEqual(0);
  });
});

/* ================================================================
 * 2. Quick mode — ARIA, recording state, VAD auto-stop
 * ================================================================ */

test.describe('Quick mode', () => {
  test('initial ARIA label is "Quick Request – tap to speak"', async ({ mockPage: page }) => {
    await expect(page.locator('#quick-btn')).toHaveAttribute(
      'aria-label',
      'Quick Request – tap to speak',
    );
    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-pressed', 'false');
  });

  test('tapping Quick sets aria-pressed=true', async ({ mockPage: page }) => {
    await startQuick(page);
    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-pressed', 'true');
  });

  test('during Quick recording aria-label changes to "Stop recording"', async ({
    mockPage: page,
  }) => {
    await startQuick(page);
    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-label', 'Stop recording');
  });

  test('during Quick recording the live-transcript panel is visible', async ({
    mockPage: page,
  }) => {
    await startQuick(page);
    await expect(page.locator('#live-transcript')).toBeVisible();
  });

  test('Quick auto-stops after 3500 ms silence (VAD)', async ({ page }) => {
    await page.clock.install();
    await page.addInitScript(MOCK_SPEECH_SCRIPT);
    await page.goto(PR_URL);

    await startQuick(page);
    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-pressed', 'true');

    await page.clock.runFor(3500);

    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-pressed', 'false');
  });

  test('after Quick auto-stop the transcript bar shows captured text', async ({ page }) => {
    await page.clock.install();
    await page.addInitScript(MOCK_SPEECH_SCRIPT);
    await page.goto(PR_URL);

    await startQuick(page);
    await page.evaluate(() =>
      (window as any).__mockRecognition._fireResult('quick mode transcript', true),
    );

    await page.clock.runFor(3500);

    await expect(page.locator('#transcript-bar')).toBeVisible();
    await expect(page.locator('#transcript-text')).toContainText('quick mode transcript');
  });

  test('silence timer resets on speech — delayed auto-stop in Quick mode', async ({ page }) => {
    await page.clock.install();
    await page.addInitScript(MOCK_SPEECH_SCRIPT);
    await page.goto(PR_URL);

    await startQuick(page);

    // Advance 2000 ms — still within initial 3500 ms window
    await page.clock.runFor(2000);
    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-pressed', 'true');

    // Speech resets the timer
    await page.evaluate(() =>
      (window as any).__mockRecognition._fireResult('some words', true),
    );

    // Advance 2000 ms more (total 4000 ms, but only 2000 ms since last speech)
    await page.clock.runFor(2000);
    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-pressed', 'true');

    // Remaining 1500 ms brings post-speech silence to 3500 ms → auto-stop
    await page.clock.runFor(1500);
    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-pressed', 'false');
  });
});

/* ================================================================
 * 3. Brainstorm mode — ARIA, continuous recording, manual stop
 * ================================================================ */

test.describe('Brainstorm mode', () => {
  test('initial ARIA label is "Brainstorm – tap for continuous recording"', async ({
    mockPage: page,
  }) => {
    await expect(page.locator('#brainstorm-btn')).toHaveAttribute(
      'aria-label',
      'Brainstorm – tap for continuous recording',
    );
    await expect(page.locator('#brainstorm-btn')).toHaveAttribute('aria-pressed', 'false');
  });

  test('tapping Brainstorm sets aria-pressed=true', async ({ mockPage: page }) => {
    await startBrainstorm(page);
    await expect(page.locator('#brainstorm-btn')).toHaveAttribute('aria-pressed', 'true');
  });

  test('during Brainstorm recording aria-label changes to "Stop brainstorm recording"', async ({
    mockPage: page,
  }) => {
    await startBrainstorm(page);
    await expect(page.locator('#brainstorm-btn')).toHaveAttribute(
      'aria-label',
      'Stop brainstorm recording',
    );
  });

  test('Brainstorm does NOT auto-stop after 3500 ms (no VAD)', async ({ page }) => {
    await page.clock.install();
    await page.addInitScript(MOCK_SPEECH_SCRIPT);
    await page.goto(PR_URL);

    await startBrainstorm(page);
    await expect(page.locator('#brainstorm-btn')).toHaveAttribute('aria-pressed', 'true');

    // Advance well past the Quick-mode VAD threshold
    await page.clock.runFor(3500);

    // Brainstorm must still be active
    await expect(page.locator('#brainstorm-btn')).toHaveAttribute('aria-pressed', 'true');
  });

  test('tapping Brainstorm again manually stops recording', async ({ mockPage: page }) => {
    await startBrainstorm(page);
    await stopBrainstorm(page);
    await expect(page.locator('#brainstorm-btn')).toHaveAttribute('aria-pressed', 'false');
  });

  test('after manual Brainstorm stop the transcript bar shows captured text', async ({
    mockPage: page,
  }) => {
    await startBrainstorm(page);
    await simulateSpeech(page, 'brainstorm session notes');
    await stopBrainstorm(page);

    await expect(page.locator('#transcript-bar')).toBeVisible();
    await expect(page.locator('#transcript-text')).toHaveText('brainstorm session notes');
  });

  test('after manual stop without speech the transcript bar stays hidden', async ({
    mockPage: page,
  }) => {
    await startBrainstorm(page);
    await stopBrainstorm(page);
    await expect(page.locator('#transcript-bar')).toBeHidden();
  });
});

/* ================================================================
 * 4. Hint text changes per active mode
 * ================================================================ */

test.describe('Hint text', () => {
  test('hint is empty on initial load (wake mode off)', async ({ mockPage: page }) => {
    await expect(page.locator('#mic-hint')).toHaveText('');
  });

  test('Quick active → hint reads "Listening… tap Quick to stop"', async ({
    mockPage: page,
  }) => {
    await startQuick(page);
    await expect(page.locator('#mic-hint')).toHaveText('Listening… tap Quick to stop');
  });

  test('Brainstorm active → hint reads "Recording… tap Brainstorm to stop"', async ({
    mockPage: page,
  }) => {
    await startBrainstorm(page);
    await expect(page.locator('#mic-hint')).toHaveText('Recording… tap Brainstorm to stop');
  });

  test('hint returns to empty after Quick stops', async ({ mockPage: page }) => {
    await startQuick(page);
    await page.click('#quick-btn'); // stop
    await page.waitForFunction(
      () => document.getElementById('quick-btn')?.getAttribute('aria-pressed') === 'false',
    );
    await expect(page.locator('#mic-hint')).toHaveText('');
  });

  test('hint returns to empty after Brainstorm stops', async ({ mockPage: page }) => {
    await startBrainstorm(page);
    await stopBrainstorm(page);
    await expect(page.locator('#mic-hint')).toHaveText('');
  });
});

/* ================================================================
 * 5. Mutual exclusion — only one mode active at a time
 * ================================================================ */

test.describe('Mutual exclusion', () => {
  test('clicking Brainstorm while Quick is active does not start Brainstorm', async ({
    mockPage: page,
  }) => {
    await startQuick(page);

    // Attempt to start Brainstorm while Quick is running
    await page.click('#brainstorm-btn');

    // Quick remains active, Brainstorm stays idle
    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-pressed', 'true');
    await expect(page.locator('#brainstorm-btn')).toHaveAttribute('aria-pressed', 'false');
  });

  test('clicking Quick while Brainstorm is active does not start Quick', async ({
    mockPage: page,
  }) => {
    await startBrainstorm(page);

    // Attempt to start Quick while Brainstorm is running
    await page.click('#quick-btn');

    // Brainstorm remains active, Quick stays idle
    await expect(page.locator('#brainstorm-btn')).toHaveAttribute('aria-pressed', 'true');
    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-pressed', 'false');
  });
});

/* ================================================================
 * 6. Wake word triggers Quick mode specifically
 * ================================================================ */

test.describe('Wake word integration', () => {
  test('"Hey Chill" wake phrase starts Quick mode, not Brainstorm', async ({ page }) => {
    await page.clock.install();
    await page.addInitScript(MULTI_INSTANCE_MOCK_SCRIPT);
    await page.goto(PR_URL);

    // Enable wake mode — this creates a second SpeechRecognition instance (wakeRecognition)
    await page.click('#wake-btn');

    // Wait for wake recognition instance to be created and started
    await page.waitForFunction(() => (window as any).__mockInstances?.length >= 2);

    // Fire the wake phrase on the wake recognition instance (index 1)
    await page.evaluate(() => {
      const wakeRecognition = (window as any).__mockInstances[1];
      wakeRecognition._fireResult('hey chill', false); // interim transcript is sufficient
    });

    // handleWakeWordDetected uses setTimeout(250 ms) before calling startListening('quick')
    await page.clock.runFor(300);

    // Quick must now be recording
    await expect(page.locator('#quick-btn')).toHaveAttribute('aria-pressed', 'true');

    // Brainstorm must NOT be recording
    await expect(page.locator('#brainstorm-btn')).toHaveAttribute('aria-pressed', 'false');
  });

  test('wake hint text shows when wake mode is enabled', async ({ mockPage: page }) => {
    await page.click('#wake-btn');
    await expect(page.locator('#mic-hint')).toHaveText('Say "Hey Chill" or tap Quick');
  });
});

